<?php defined('ABSPATH') || exit; $settings=new FounderKit_Settings(); $meta=['fk-hero'=>'FK Hero','fk-stats-counter'=>'FK Stats Counter','fk-case-study'=>'FK Case Study','fk-portfolio-grid'=>'FK Portfolio Grid','fk-tech-stack'=>'FK Tech Stack','fk-pricing-table'=>'FK Pricing Table','fk-quiz-embed'=>'FK Quiz Embed','fk-course-card'=>'FK Course Card','fk-timeline'=>'FK Timeline','fk-digital-product-card'=>'FK Digital Product Card','fk-testimonial-carousel'=>'FK Testimonial Carousel','fk-job-listing'=>'FK Job Listing','fk-team-member'=>'FK Team Member','fk-membership-cta'=>'FK Membership CTA','fk-resource-card'=>'FK Resource Card']; ?><div class="fk-admin-wrap"><div class="fk-admin-header"><h1><?php esc_html_e('Block Manager','founderkit'); ?></h1></div><div class="fk-blocks-grid"><?php wp_nonce_field('founderkit_blocks_toggle','founderkit_blocks_nonce'); ?><?php foreach($meta as $slug=>$label): $on=$settings->is_block_enabled($slug); ?><div class="fk-block-item <?php echo $on?'is-enabled':'is-disabled'; ?>"><div class="fk-block-info"><strong><?php echo esc_html($label); ?></strong><span><?php echo esc_html($slug); ?></span></div><label class="fk-toggle"><input type="checkbox" <?php checked($on); ?> data-block="<?php echo esc_attr($slug); ?>" class="fk-block-toggle"><span class="fk-toggle-slider"></span></label></div><?php endforeach; ?></div></div>
